def fold_match(value: str) -> str:
    """Lowercase, strip accents, collapse spaces (for comparing labels to buttons)."""
    norm = unicodedata.normalize("NFD", value.strip().lower())
    norm = "".join(c for c in norm if unicodedata.category(c) != "Mn")
    return "".join(norm.split())


