def button_matches_choice(
    button_text: str, target: str, display_name: str, mode: str
) -> bool:
    raw_btn = (button_text or "").strip()
    if not raw_btn:
        return False
    t_fold = fold_match(target)
    f_fold = fold_match(display_name)
    b_fold = fold_match(raw_btn)
    b_compact = b_fold.replace(" ", "")
    t_compact = t_fold.replace(" ", "")
    f_compact = f_fold.replace(" ", "")
    if b_fold == t_fold or b_fold == f_fold:
        return True
    if b_compact == t_compact or b_compact == f_compact:
        return True
    if t_compact and (t_compact in b_compact or b_compact in t_compact):
        return True
    if f_compact and (f_compact in b_compact or b_compact in f_compact):
        return True
    if mode == "last" and t_compact:
        parts = raw_btn.lower().split()
        if parts and fold_match(parts[-1]) == t_compact:
            return True
    if mode == "first" and t_compact:
        parts = raw_btn.lower().split()
        if parts and fold_match(parts[0]) == t_compact:
            return True
    return False


